class NetworkLogger {
    static let shared = NetworkLogger()
    private let analytics = AnalyticsLogger.shared
    
    private init() {}
    
    func logRequest(url: URL, method: String, headers: [String: String]?, body: Data?, userId: String?) {
        let endpoint = url.path
        analytics.logAPIRequest(endpoint: endpoint, method: method, userId: userId)
        
        if let body = body,
           let json = try? JSONSerialization.jsonObject(with: body) as? [String: Any] {
            analytics.logAPIPayload(endpoint: endpoint, payload: json, isRequest: true)
        }
    }
    
    func logResponse(url: URL, statusCode: Int, data: Data?, duration: TimeInterval, error: Error?) {
        let endpoint = url.path
        
        if let error = error {
            analytics.logNetworkError(endpoint: endpoint, error: error)
        } else {
            analytics.logAPIResponse(endpoint: endpoint, statusCode: statusCode, duration: duration)
            
            if statusCode >= 400 {
                let errorMessage = HTTPURLResponse.localizedString(forStatusCode: statusCode)
                analytics.logAPIError(endpoint: endpoint, statusCode: statusCode, errorMessage: errorMessage)
            }
            
            if let data = data,
               let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] {
                analytics.logAPIPayload(endpoint: endpoint, payload: json, isRequest: false)
            }
        }
    }
}

class UserActivityTracker {
    static let shared = UserActivityTracker()
    private let analytics = AnalyticsLogger.shared
    
    private init() {}
    
    func trackLogin(userId: String, email: String, method: String) {
        analytics.logAuthenticationSuccess(userId: userId, email: email)
        analytics.logUserAction(userId: userId, action: "login", metadata: ["method": method])
    }
    
    func trackLoginFailure(email: String, reason: String) {
        analytics.logAuthenticationFailure(email: email, reason: reason)
    }
    
    func trackLogout(userId: String) {
        analytics.logLogout(userId: userId)
    }
    
    func trackProfileUpdate(userId: String, fields: [String]) {
        for field in fields {
            analytics.logUserDataChange(userId: userId, field: field, changeType: "update")
        }
    }
    
    func trackScreenView(screenName: String, userId: String?) {
        analytics.logScreenView(screenName: screenName, userId: userId)
    }
    
    func trackButtonTap(buttonName: String, screenName: String, userId: String?) {
        analytics.logUserAction(userId: userId ?? "anonymous", action: "button_tap", metadata: [
            "button": buttonName,
            "screen": screenName
        ])
    }
    
    func trackError(error: Error, context: String, userId: String? = nil) {
        analytics.logError(error: error, context: context, userId: userId)
    }
}

extension URLSession {
    func dataTaskWithLogging(with request: URLRequest, userId: String? = nil, completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) -> URLSessionDataTask {
        let startTime = Date()
        
        NetworkLogger.shared.logRequest(
            url: request.url!,
            method: request.httpMethod ?? "GET",
            headers: request.allHTTPHeaderFields,
            body: request.httpBody,
            userId: userId
        )
        
        return dataTask(with: request) { data, response, error in
            let duration = Date().timeIntervalSince(startTime)
            let statusCode = (response as? HTTPURLResponse)?.statusCode ?? 0
            
            NetworkLogger.shared.logResponse(
                url: request.url!,
                statusCode: statusCode,
                data: data,
                duration: duration,
                error: error
            )
            
            completionHandler(data, response, error)
        }
    }
